{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a variation of a Minimum Spanning Tree or Steiner Tree problem on a 2D grid with directed edges (monotonicity constraint). The goal is to minimize the total Manhattan distance cost C while ensuring all target points are reachable from (0,0) via a valid sequence of operations.",
  "helpers": [
    {
      "label": "graph_theory_specialist",
      "instructions": "Analyze the problem as a directed Steiner Tree problem on a 2D grid where edges must satisfy tx >= fx and ty >= fy. Determine if a Minimum Spanning Tree approach using Manhattan distance, modified for the monotonicity constraint, provides a strong baseline. Specifically, evaluate if a greedy approach that connects each point to its nearest existing point in the lower-left quadrant is optimal or near-optimal."
    },
    {
      "label": "algorithm_designer",
      "instructions": "Design a greedy construction algorithm that maintains a set of 'already created' beverages. For each target beverage (ai, bi) not yet in the set, find an existing beverage (fx, fy) such that fx <= ai and fy <= bi, minimizing the cost (ai - fx) + (bi - fy). Propose an efficient way to select the order of target beverages to process (e.g., sorting by x+y or using a sweep-line approach) to minimize the total cost C."
    },
    {
      "label": "complexity_analyst",
      "instructions": "Analyze the computational complexity of the proposed greedy algorithm. Given N=1000, ensure that the search for the best (fx, fy) for each target point can be performed in O(N^2) or O(N log N) time to stay well within typical competitive programming time limits."
    }
  ],
  "synthesis_brief": "Combine the graph theory analysis and the greedy algorithm design into a single Python implementation. The final solution should sort target points to facilitate a monotonic construction, use a greedy search to find the cheapest valid parent for each point, and output the operations in a valid sequence."
}

